// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "../RubicAggregator.sol";

contract RubicAggregatorTest is Test {
    RubicAggregator public aggregator;

    function setUp() public {
        aggregator = new RubicAggregator();
    }

    function testDeposit() public {
        uint256 amount = 1 ether;
        aggregator.deposit{value: amount}();
        assertEq(aggregator.getUserBalance(address(this)), amount);
    }

    function testWithdraw() public {
        uint256 amount = 1 ether;
        aggregator.deposit{value: amount}();
        aggregator.withdraw(amount);
        assertEq(aggregator.getUserBalance(address(this)), 0);
    }

    function testReentrancyGuard() public {
        uint256 amount = 1 ether;
        aggregator.deposit{value: amount}();

        // Attempt to withdraw in a reentrant way
        vm.expectRevert(bytes("ReentrancyGuard: reentrant call"));
        aggregator.withdraw(amount);
    }

    function testInsufficientBalance() public {
        uint256 amount = 1 ether;
        vm.expectRevert(bytes("Insufficient balance"));
        aggregator.withdraw(amount);
    }

    function testZeroWithdrawal() public {
        uint256 amount = 1 ether;
        aggregator.deposit{value: amount}();
        vm.expectRevert(bytes("Withdrawal amount must be greater than 0"));
        aggregator.withdraw(0);
    }

    function testZeroDeposit() public {
        vm.expectRevert(bytes("Deposit amount must be greater than 0"));
        aggregator.deposit{value: 0}();
    }
}
